record_types.code:
type RTC_Date is record
   Day_Of_Week : RTC_Day_Of_Week;
   Day         : RTC_Day;
   Month       : RTC_Month;
   Year        : RTC_Year;
end record;

type RTC_Time is record
   Hour : RTC_Hour;
   Min  : RTC_Minute;
   Sec  : RTC_Second;
end record;

subprograms.code:
procedure Get (This : in out RTC_Device;
               Time : out RTC_Time;
               Date : out RTC_Date)

procedure Set (This : in out RTC_Device;
               Time : RTC_Time;
               Date : RTC_Date)
